'use server'

import axios from 'axios';
import https from 'https';
import * as xlsx from 'xlsx';
import fs from 'fs';
import path from 'path';

export async function actionExtractDaftarBarang() {
    const httpsAgent = new https.Agent({ family: 4, rejectUnauthorized: false, keepAlive: true });
    const params = {
        '__EVENTTARGET': '',
        '__EVENTARGUMENT': '',
        '__LASTFOCUS': '',
        '__VIEWSTATE': '',
        '__VIEWSTATEGENERATOR': '0E8F9E58',
        '__EVENTVALIDATION': '',
        'ctl00$Isi$DdlThn': '2026',
        'ctl00$Isi$DdlJnsAset': '1',
        'ctl00$Isi$DdlPeriodeLap': '23',
        'ctl00$Isi$DdlIe': '0',
        'ctl00$Isi$RdTutup': '0',
        'ctl00$Isi$DdlOrg': '3',
        'ctl00$Isi$DdlPB': '01.00.00',
        'ctl00$Isi$TxtTglTtd': '20/05/2026',
        'ctl00$Isi$DdlPegKanan': '0',
        'ctl00$Isi$TxtJabKanan': '',
        'ctl00$Isi$Button2': 'Export Ke Excel'
    }
    const add = {
        params: {
            'kib': '2',
            'Periode': '2026',
            'isskpd': '1',
            'usrid': '884'
        },
        headers: {
            'Content-Type': 'application/x-www-form-urlencoded',
            'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/124.0.0.0 Safari/537.36',
            'accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,image/avif,image/webp,image/apng,*/*;q=0.8,application/signed-exchange;v=b3;q=0.7',
            'accept-language': 'en-US,en;q=0.9,id;q=0.8',
            'cache-control': 'max-age=0',
            'origin': 'https://ebmd.pasuruankab.go.id',
            'priority': 'u=0, i',
            'referer': 'https://ebmd.pasuruankab.go.id/ebmd_rpt/AST_daftarbarang/dbpb_param.aspx?kib=2&Periode=2026&isskpd=1&usrid=884',
            'sec-ch-ua': '"Chromium";v="148", "Google Chrome";v="148", "Not/A)Brand";v="99"',
            'sec-ch-ua-mobile': '?0',
            'sec-ch-ua-platform': '"Windows"',
            'sec-fetch-dest': 'document',
            'sec-fetch-mode': 'navigate',
            'sec-fetch-site': 'same-origin',
            'sec-fetch-user': '?1',
            'upgrade-insecure-requests': '1',
            'user-agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/148.0.0.0 Safari/537.36',
            'cookie': '_ga=GA1.3.1310505215.1777637860; _gid=GA1.3.951371392.1779099639; _ga_3LFLRFSZV4=GS2.3.s1779277472$o13$g0$t1779277472$j60$l0$h0; ebmdpasuruan_session=a%3A5%3A%7Bs%3A10%3A%22session_id%22%3Bs%3A32%3A%227030cbe1f9946101f6fe2a6927860c74%22%3Bs%3A10%3A%22ip_address%22%3Bs%3A13%3A%22114.5.240.152%22%3Bs%3A10%3A%22user_agent%22%3Bs%3A111%3A%22Mozilla%2F5.0+%28Windows+NT+10.0%3B+Win64%3B+x64%29+AppleWebKit%2F537.36+%28KHTML%2C+like+Gecko%29+Chrome%2F148.0.0.0+Safari%2F537.36%22%3Bs%3A13%3A%22last_activity%22%3Bi%3A1779288136%3Bs%3A9%3A%22user_data%22%3Bs%3A0%3A%22%22%3B%7D63dae4464dc8a97ce0b39951e409e7c4735617f8'
        },
        httpsAgent: httpsAgent,
        responseType: 'arraybuffer', // Sangat penting!
        timeout: 60000, // 60 detik sudah cukup. Jika lebih, berarti server E-BMD-nya yang down.
        maxContentLength: 50 * 1024 * 1024, // Batasi maksimal 50MB agar tidak memory leak
    }
    try {
        // TAHAP 1: TRIGGER PEMBUATAN FILE DI SERVER
        const postResponse = await axios.post(
            'https://ebmd.pasuruankab.go.id/ebmd_rpt/AST_daftarbarang/dbpb_param.aspx',
            new URLSearchParams(params), add
        );

        // Validasi jika server membalas HTML (biasanya Error 500 atau Sesi Habis)
        const contentType = postResponse.headers['content-type'];
        if (contentType && (contentType.includes('text/html') || contentType.includes('text/plain'))) {
            const htmlString = Buffer.from(postResponse.data).toString('utf-8');

            // Jika isinya sangat pendek (misal pesan error), simpan untuk debug
            if (htmlString.length < 5000) {
                const debugPath = path.join(process.cwd(), 'debug-ebmd-error.html');
                fs.writeFileSync(debugPath, htmlString);
                return { success: false, error: "Server mengembalikan HTML, kemungkinan sesi habis. Cek debug-ebmd-error.html" };
            }
        }

        // console.log("Excel biner berhasil diterima. Mulai proses penyimpanan...");

        // TAHAP 1.5: SIMPAN FILE RAW KE DISK (Untuk verifikasi manual)
        const buffer = Buffer.from(postResponse.data);
        const fileName = `debug_bmd_${Date.now()}.xlsx`;
        const filePath = path.join(process.cwd(), fileName); // Disimpan di root project

        fs.writeFileSync(filePath, buffer);
        // console.log(`File berhasil disimpan di: ${filePath}`);

        // TAHAP 2: PARSING (Seperti sebelumnya)
        const workbook = xlsx.read(buffer, { type: 'buffer' });
        const firstSheetName = workbook.SheetNames[0];

        // Gunakan range: 9 untuk skip 9 baris header yang kosong/metadata
        const rawData = xlsx.utils.sheet_to_json(workbook.Sheets[firstSheetName], {
            range: 9,
            defval: null
        });

        const sanitizedData = JSON.parse(JSON.stringify(rawData));

        return {
            success: true,
            count: sanitizedData.length,
            fileName: fileName, // Kembalikan nama file agar Anda tahu file mana yang dibuka
            data: sanitizedData
        };
        // console.log("Excel biner berhasil diterima. Mulai parsing...");

        // // TAHAP 2: PARSING
        // const buffer = Buffer.from(postResponse.data);
        // const workbook = xlsx.read(buffer, { type: 'buffer' });

        // // Ambil sheet pertama
        // const firstSheetName = workbook.SheetNames[0];
        // const rawData = xlsx.utils.sheet_to_json(workbook.Sheets[firstSheetName], { defval: null });

        // console.log(`Ekstraksi Selesai: ${rawData.length} baris.`);

        // return {
        //     success: true,
        //     count: rawData.length,
        //     data: rawData
        // };

    } catch (error: any) {
        return { success: false, error: error.message };
    }
}